import os
import json
import re
from collections import defaultdict

def analyze_chats(context_dir):
    files = [f for f in os.listdir(context_dir) if f.endswith('.md') and f.startswith('DeepSeek')]

    analysis = {
        "total_files": len(files),
        "topics": defaultdict(int),
        "time_distribution": defaultdict(int),
        "keywords": defaultdict(int),
        "file_sizes": [],
        "user_persona": {
            "disciplines": defaultdict(int),
            "interaction_types": defaultdict(int)
        }
    }

    topic_mapping = {
        "Coding & Development": ["代码", "Python", "NumPy", "HuggingFace", "环境", "SSH", "命令", "脚本", "bug", "依赖", "git", "配置", "模块缺失", "解决", "报错", "Anaconda", "Slurm", "服务器", "Hugging Face"],
        "Machine Learning & NLP": ["模型", "强化学习", "训练", "微调", "RAG", "大模型", "数据集", "算法", "TTS", "CosyVoice", "语音合成", "Word2Vec", "LLM", "神经网络", "预训练"],
        "Computer Vision & Robotics": ["图像处理", "计算机视觉", "机械臂", "Dofbot", "相机标定", "双目立体视觉", "边缘检测", "特征匹配", "机器人", "SIFT", "RANSAC", "消失点", "动力学", "运动学", "极几何", "几何变换"],
        "Mathematics & Logic": ["数学", "逻辑", "图算法", "概率", "矩阵", "计算题", "证明", "PageRank", "Flajolet-Martin", "Jaccard", "模块度", "统计", "条件概率"],
        "Bioinformatics": ["基因", "蛋白", "序列", "DNA", "His-tag", "变异", "Evo", "Cauldron", "Primerize"],
        "Academic & Writing": ["报告", "作业", "翻译", "撰写", "LaTeX", "总结", "评价", "议论文", "心得", "申请", "笔记", "社会实践", "随母姓", "性别理论"]
    }

    for filename in files:
        filepath = os.path.join(context_dir, filename)
        size = os.path.getsize(filepath)
        analysis["file_sizes"].append({"file": filename, "size": size})

        # Categorize by topic based on filename
        matched = False
        for topic, keywords in topic_mapping.items():
            if any(keyword.lower() in filename.lower() for keyword in keywords):
                analysis["topics"][topic] += 1
                analysis["user_persona"]["disciplines"][topic] += 1
                matched = True

        if not matched:
            analysis["topics"]["Other / General"] += 1

        # Analyze interaction types based on filename clues
        if any(w in filename for w in ["报错", "失败", "问题", "解决", "修复", "Error", "Fails", "Fix", "排查"]):
            analysis["user_persona"]["interaction_types"]["Troubleshooting"] += 1
        elif any(w in filename for w in ["作业", "习题", "解答", "计算题", "证明", "测验", "题目", "Homework"]):
            analysis["user_persona"]["interaction_types"]["Homework & Study"] += 1
        elif any(w in filename for w in ["报告", "撰写", "翻译", "总结", "笔记", "LaTeX", "格式", "排版"]):
            analysis["user_persona"]["interaction_types"]["Writing & Formatting"] += 1
        elif any(w in filename for w in ["实现", "代码", "开发", "脚本", "配置"]):
            analysis["user_persona"]["interaction_types"]["Implementation & Coding"] += 1
        else:
            analysis["user_persona"]["interaction_types"]["General Query"] += 1

    # Calculate some stats
    analysis["topics"] = dict(sorted(analysis["topics"].items(), key=lambda item: item[1], reverse=True))
    analysis["user_persona"]["disciplines"] = dict(sorted(analysis["user_persona"]["disciplines"].items(), key=lambda item: item[1], reverse=True))
    analysis["user_persona"]["interaction_types"] = dict(sorted(analysis["user_persona"]["interaction_types"].items(), key=lambda item: item[1], reverse=True))

    with open('analysis.json', 'w', encoding='utf-8') as f:
        json.dump(analysis, f, ensure_ascii=False, indent=2)

if __name__ == "__main__":
    analyze_chats('context')
EOF
